  ('elementary-e0adf6cd-moex-00570', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '有關幼兒教育及照顧法之規定，下列敘述何者正確？', '["幼兒係指二歲以上至入幼稚園前之人", "主管機關應對幼兒之父母或監護人主動提供幼兒園評鑑報告及結果", "教保服務機構應公開教保服務人員及其他服務人員學（經）歷及證照之資訊", "教保服務人員係指提供教保服務之教師、教保員及助理教保員，而園長不列在其中"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00571', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '有關國民教育法及其施行細則之規定，下列敘述何者錯誤？', '["國民小學及國民中學學生免納學費", "凡六歲至十五歲之國民，應受國民教育", "已逾齡未受國民教育之國民，應受短期補習教育", "國民小學及國民中學之設置以不超過四十八班為原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
