  ('elementary-e0adf6cd-moex-00573', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '有關高級中等教育法之規定，下列敘述何者錯誤？', '["十二年國民基本教育中，九年國民教育依國民教育法規定，採免試、免學費及強迫入學", "申請免試入學人數未超過各該主管機關核定之名額者，全額錄取", "高級中等學校每班置導師一人，由校長就專任及代理教師聘兼之", "學生因懷孕、分娩或撫育三歲以下子女，得延長修業期限，至多四年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00574', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '有關師資培育之大學及教育實習機構辦理教育實習辦法之規定，下列敘述何者錯誤？', '["實習輔導教師，應為具有三年以上教學年資之編制內專任教師", "教育實習之學科、領域、群科為稀有類科，其輔導實習學生人數至多三人", "教育實習機構位於偏遠地區、偏鄉地區及境外，其輔導實習學生人數至多三人", "教學實習輔導員，應具有與協同實習輔導之科目相近學術領域，三年以上教學年資"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00575', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '有關特殊教育法之規定，下列敘述何者錯誤？', '["特殊教育之實施分為學前、國民及高級中等教育三個教育階段", "國民教育階段學校資賦優異教育之實施採分散式資源班辦理", "為推展身心障礙兒童之早期療育，應自二歲開始實施特殊教育", "地方政府編列特殊教育預算，不得低於當年度教育主管預算百分之五"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00576', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據原住民族教育法及其施行細則之相關規定，下列敘述何者錯誤？', '["原住民族地區之原住民重點學校，應每四學年重新認定一次", "原住民教育班係指為原住民學生教育需要，於一般學校中開設之班級", "師資培育大學之原住民公費生畢業前，應取得中高級以上之原住民族語言能力證明書", "在原住民族地區，該校原住民學生人數達學生總數三分之一以上者，認定為原住民重點學校"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
