  ('elementary-e0adf6cd-moex-00578', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據大學系統組織及運作辦法之規定，下列敘述何者錯誤？', '["大學系統得對外募集經費，分配予各學校負責執行", "大學組成大學系統，應經參與系統學校行政會議通過", "大學系統主席為無給職，任期不得逾四年，期滿得續聘一次", "大學系統內各學校教師借調，得不受義務返校授課規定之限制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
